#pragma OPENCL EXTENSION cl_khr_fp64 : enable

__kernel void Fan1(__global float *m, __global float *a, int Size, int t)
{   
    int idx = get_global_id(0);
    if(idx >= Size - 1 - t) return;
    int row = idx + t + 1;
    m[row * Size + t] = a[row * Size + t] / a[t * Size + t];
}

__kernel void Fan2(__global float *m, __global float *a, __global float *b, int Size, int j1, int t)
{
    int xidx = get_global_id(0);
    int yidx = get_global_id(1);

    if(xidx >= Size - 1 - t) return;
    if(yidx >= Size - t) return;

    int row = xidx + 1 + t;
    int col = yidx + t;
    a[row * Size + col] -= m[row * Size + t] * a[t * Size + col];

    if(yidx == 0){
        b[row] -= m[row * Size + t] * b[t];
    }
}
